class Admin_Model_Parameter extends Admin_Model_Base_Parameter {

    const FILTER_TYPE_BASIC = 'basic';
    const FILTER_TYPE_COLOR = 'color';


    public function save(Doctrine_Connection $conn = null) {
        $isNew = $this->ID == null;

        parent::save($conn);
    }

    public static function getFilterTypes(): array {
        return [
            self::FILTER_TYPE_BASIC => 'základní',
            self::FILTER_TYPE_COLOR => 'barva'
        ];
    }

    public static function getParameterByCode($code) {
        return Doctrine_Query::create()
            ->from('Admin_Model_Parameter p')
            ->where('p.Code = ?', $code)
            ->fetchOne();
    }
}